+            BehaviorEquivalenceClass::Equivalent,
+            BehaviorEquivalenceClass::BenchmarkNoise,
+            BehaviorEquivalenceClass::InfraFailure,
+            BehaviorEquivalenceClass::UnsupportedFeature,
