+    );
+    let mut a = CounterexampleArchive::new();
+    a.ingest(&r);
+    assert_eq!(a.total_count, 1);
+    // Second ingest adds another counterexample (not deduplicated)
+    a.ingest(&r);
+    assert_eq!(a.total_count, 2);
